BNNModel::BNNModel() {}

float BNNModel::predict(const float* input) {
    float* temp;
    for (int i = 0; i < 1; i++) input_buffer[i] = input[i];

    float* current_in = input_buffer;
    float* current_out = hidden_buffer;
    int current_size = 1;

    // Linear layer 0
    for (int i = 0; i < 64; i++) {
        float acc = 0.0f;
        for (int j = 0; j < 1; j++) {
            acc += w0_mu[i][j] * current_in[j];
        }
        acc += b0_mu[i];
        current_out[i] = acc;
    }
    temp = current_in;
    current_in = current_out;
    current_out = temp;
    current_size = 64;

    // Activation relu
    for (int i = 0; i < current_size; i++) {
        if (current_in[i] < 0) current_in[i] = 0;
    }

    // Linear layer 2
    for (int i = 0; i < 64; i++) {
        float acc = 0.0f;
        for (int j = 0; j < 64; j++) {
            acc += w2_mu[i][j] * current_in[j];
        }
        acc += b2_mu[i];
        current_out[i] = acc;
    }
    temp = current_in;
    current_in = current_out;
    current_out = temp;
    current_size = 64;

    // Activation relu
    for (int i = 0; i < current_size; i++) {
        if (current_in[i] < 0) current_in[i] = 0;
    }

    // Linear layer 4
    for (int i = 0; i < 1; i++) {
        float acc = 0.0f;
        for (int j = 0; j < 64; j++) {
            acc += w4_mu[i][j] * current_in[j];
        }
        acc += b4_mu[i];
        current_out[i] = acc;
    }
    temp = current_in;
    current_in = current_out;
    current_out = temp;
    current_size = 1;

    return current_in[0];
}